const items = $input.all();
const contacts = items.filter(i => i.json.properties?.email);
const productMilestones = items.filter(i => i.json.account_id && i.json.milestones);

// Build product milestone lookup by email
const pmLookup = {};
productMilestones.forEach(pm => { pmLookup[pm.json.email] = pm.json.milestones || []; });

const STALL_THRESHOLDS = { 'starter': [7,14,21,30,45], 'growth': [10,21,30,45,60], 'enterprise': [21,30,45,60,90] };
const MILESTONE_NAMES = ['Onboarded','Integration Connected','Team Expanded','First Outcome Achieved','Advanced Feature Adopted'];

const now = Date.now();
const actions = [];

contacts.forEach(contact => {
  const p = contact.json.properties;
  const plan = p.plan_type?.value || 'growth';
  const thresholds = STALL_THRESHOLDS[plan] || STALL_THRESHOLDS.growth;
  const email = p.email?.value;
  const days_in_stage = parseInt(p.days_in_stage?.value || 0);
  const last_action = p.last_milestone_action_at?.value;
  const hrs_since_action = last_action ? (now - new Date(last_action).getTime())/(1000*60*60) : 9999;
  if (hrs_since_action < 24) return; // Don't re-trigger within 24h

  const milestones = [p.milestone_1?.value, p.milestone_2?.value, p.milestone_3?.value, p.milestone_4?.value, p.milestone_5?.value].map(v => v === 'true');
  const product_milestones = pmLookup[email] || [];
  const current_stage = milestones.filter(Boolean).length;

  // Check for new completion (product API shows completed today but HubSpot not updated yet)
  const new_completion = product_milestones.find(pm => pm.completed_today && !milestones[pm.index]);
  if (new_completion) { actions.push({ json: { contact_id: contact.json.id, email, firstname: p.firstname?.value, company: p.company?.value, plan, action_type: 'milestone_completed', milestone_index: new_completion.index, milestone_name: MILESTONE_NAMES[new_completion.index], cs_owner: p.cs_owner?.value } }); return; }

  // All milestones complete?
  if (current_stage >= 5) { actions.push({ json: { contact_id: contact.json.id, email, firstname: p.firstname?.value, company: p.company?.value, plan, action_type: 'journey_complete', cs_owner: p.cs_owner?.value } }); return; }

  // Stall detection
  const stall_threshold = thresholds[current_stage] || 30;
  if (days_in_stage > stall_threshold) { actions.push({ json: { contact_id: contact.json.id, email, firstname: p.firstname?.value, company: p.company?.value, plan, action_type: 'journey_stalled', current_stage, current_milestone: MILESTONE_NAMES[current_stage], days_stalled: days_in_stage, stall_threshold, cs_owner: p.cs_owner?.value } }); }
});

return actions;
